</dt><dd><?=fmt($a['destinations_count'])?></dd></div><div><dt>Hubs</dt><dd><?=e($a['hubs']?:'—')?></dd></div><div><dt>Alliance</dt><dd><?=e($a['alliance']?:'—')?></dd></div><div><dt>Parent</dt><dd><?=e($a['parent_company']?:'—')?></dd></div><div><dt>Last modified</dt><dd><?=e($a['date_modified']?:'—')?></dd></div></dl></div><div class="panel dark"><div class="eyebrow">Linked intelligence</div><div class="stats-grid compact"><div class="stat-card darkstat"><strong><?=nfmt(count($fleet))?></strong><span>Aircraft</span></div><div class="stat-card darkstat"><strong><?=nfmt(count($routes)+count($dests))?></strong><span>Routes / destinations</span></div></div></div></div><section class="section-head"><div><div class="eyebrow">Routes and competitors</div><h2>Network</h2></div><p>Normalised route services use airports, schedules and equipment. Legacy destination rows are retained as fallback.</p></section><?php if($routes): ?><?=render_result_table($routes)?><?php else: ?><?=render_result_table($dests)?><?php endif; ?><section class="section-head"><div><div class="eyebrow">Fleet linkage</div><h2>Aircraft</h2></div><p>Aircraft matched by operator ICAO/name. Ownership history is reserved for Pro+ users.</p></section><?php if(feature_allowed('aircraft_history')): ?><?=render_result_table($fleet)?><?php else: ?><?=access_gate('Aircraft history is a Pro feature','The fleet list preview is available, but past owners, lessors, engines and cabin configuration require Pro access.','Upgrade to Pro')?><?php endif; ?></section><?php endif; ?>
<?php elseif($page === 'airports'): $q=getv('q');$country=getv('country','all');$where=[];$params=[];if($country!=='all'){$where[]='country_code=?';$params[]=$country;}if($q!==''){$where[]='(airport_name LIKE ? OR city_name LIKE ? OR iata_code LIKE ? OR icao_code LIKE ?)';for($i=0;$i<4;$i++)$params[]='%'.$q.'%';}$w=$where?'WHERE '.implode(' AND ',$where):'';$list=rows("SELECT ap.*, c.name country_name FROM airports ap LEFT JOIN countries c ON c.code=ap.country_code $w ORDER BY airport_name LIMIT 300",$params); ?><section class="view"><section class="section-head"><div><div class="eyebrow">Airport master data</div><h2>Airports</h2></div><p>Airport records include codes, city, geolocation, elevation and hub/base relationships.</p></section><div class="filters panel"><form method="get"><input type="hidden" name="page" value="airports"><input name="q" value="<?=e($q)?>" placeholder="Search airport, city, code…"><select name="country" data-auto-submit><?=option_tags(country_options(),$country,'All countries')?></select><button class="btn ink">Search</button></form></div><div class="card-grid"><?php foreach($list as $ap): ?><article class="record-card" style="--h:<?=hue($ap['airport_name']?:$ap['iata_code'])?>"><div class="topline"><span class="chip gold"><?=e($ap['country_name']?:$ap['country_code'])?></span><span class="chip"><?=e($ap['elevation_ft']?'Elev. '.$ap['elevation_ft'].' ft':'Airport')?></span></div><h3><?=e($ap['airport_name']?:'Unnamed airport')?></h3><p><?=e($ap['city_name']?:'—')?></p><div class="code-row"><?php if($ap['iata_code']): ?><span class="chip">IATA <?=e($ap['iata_code'])?></span><?php endif; ?><?php if($ap['icao_code']): ?><span class="chip">ICAO <?=e($ap['icao_code'])?></span><?php endif; ?></div></article><?php endforeach; ?></div></section>
