<?php elseif($page === 'routes'): if(!feature_allowed('route_intelligence')): echo access_gate('Route intelligence requires an Analyst account','Routes combine airports, schedules, equipment and competitors. This is one of the core paid product areas.','View tiers'); else: $routes=rows("SELECT ars.id, CONCAT(o.iata_code,'-',d.iata_code) route, a.name airline, ars.flight_number_prefix, ars.status, rsp.frequency_per_week, rsp.departure_time_local, rsp.arrival_time_local, GROUP_CONCAT(DISTINCT atp.icao_code SEPARATOR ', ') equipment FROM airline_route_services ars JOIN airlines a ON a.id=ars.airline_id JOIN route_markets rm ON rm.id=ars.route_market_id JOIN airports o ON o.id=rm.origin_airport_id JOIN airports d ON d.id=rm.destination_airport_id LEFT JOIN route_schedule_patterns rsp ON rsp.airline_route_service_id=ars.id LEFT JOIN route_service_equipment rse ON rse.airline_route_service_id=ars.id LEFT JOIN aircraft_types atp ON atp.id=rse.aircraft_type_id GROUP BY ars.id,o.iata_code,d.iata_code,a.name,ars.flight_number_prefix,ars.status,rsp.frequency_per_week,rsp.departure_time_local,rsp.arrival_time_local ORDER BY route, airline"); ?><section class="view"><section class="section-head"><div><div class="eyebrow">Route intelligence</div><h2>Routes, equipment and competitors</h2></div><p>The route model separates airport-pair markets from airline services, schedules, aircraft equipment and traffic statistics.</p></section><?=render_result_table($routes)?><section class="section-head"><div><div class="eyebrow">Competitive markets</div><h2>Routes with more than one operator</h2></div></section><?=chart_bars(run_insight_query('routes_with_competition'))?></section><?php endif; ?>
<?php elseif($page === 'regulatory'): if(!feature_allowed('regulatory_intelligence') && $user): echo access_gate('Regulatory intelligence requires Analyst+','AOC data, authorities, bilateral rights and regulatory documents are high-value datasets.','Upgrade'); else: $q=getv('q');$country=getv('country','all');$where=[];$params=[];if($country!=='all'){$where[]='r.country_code=?';$params[]=$country;}if($q!==''){$where[]='(r.name LIKE ? OR r.regulator_name LIKE ? OR r.airline_iata LIKE ? OR r.airline_icao LIKE ? OR r.aoc_number LIKE ? OR r.authority LIKE ? OR r.city LIKE ?)';for($i=0;$i<7;$i++)$params[]='%'.$q.'%';}$w=$where?'WHERE '.implode(' AND ',$where):'';$list=rows("SELECT r.*, c.name country_name FROM regulatory_records r LEFT JOIN countries c ON c.code=r.country_code $w ORDER BY r.country_code,r.type,r.name LIMIT 300",$params); ?><section class="view"><section class="section-head"><div><div class="eyebrow">Regulatory intelligence</div><h2>Regulatory</h2></div><p>Regulators, AOC records, civil aviation authorities and contact fields. The new schema adds AOCs, documents, bilateral agreements and traffic rights.</p></section><div class="filters panel"><form method="get"><input type="hidden" name="page" value="regulatory"><input name="q" value="<?=e($q)?>" placeholder="Search authority, AOC, airline…"><select name="country" data-auto-submit><?=option_tags(country_options(),$country,'All countries')?></select><button class="btn ink">Search</button></form></div><div class="card-grid"><?php foreach($list as $r): ?><article class="record-card" style="--h:<?=hue($r['name']?:$r['type'])?>"><div class="topline"><span class="chip gold"><?=e($r['type'])?></span><?=status_chip($r['status_bucket'])?></div><h3><?=e($r['name'])?></h3><p><?=e($r['country_name']?:$r['country_code'])?><?=$r['city']?' · '.e($r['city']):''?></p><div class="code-row"><?php if($r['aoc_number']): ?><span class="chip">AOC <?=e($r['aoc_number'])?></span><?php endif; ?><?php if($r['airline_icao']): ?><span class="chip">ICAO <?=e($r['airline_icao'])?></span><?php endif; ?></div></article><?php endforeach; ?></div></section><?php endif; ?>
