en" name="action" value="admin_update_user_tier"><input name="user_id" placeholder="User ID"><select name="tier_id"><?php foreach($tiers as $t): ?><option value="<?=e($t['id'])?>"><?=e($t['name'])?></option><?php endforeach; ?></select><button class="btn ink">Update</button></form></div><?=render_result_table($users)?><?php elseif($tab==='tiers'): ?><div class="pricing-grid"><?php foreach($tiers as $tier): ?><article class="pricing-card"><h3><?=e($tier['name'])?></h3><p><?=e($tier['description'])?></p><div class="price">$<?=e($tier['monthly_usd'])?></div><ul><?php foreach(tier_features((int)$tier['id']) as $f): ?><li><?=e($f['feature_label'])?></li><?php endforeach; ?></ul></article><?php endforeach; ?></div><?php endif; ?></section><?php endif; ?>
